#include<bits/stdc++.h>
using namespace std;
int a[210],dp[210][210];
int main()
{
    int n;
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&a[i]);
        a[i+n]=a[i];
    }
    for(int len=2;len<=n+1;len++)
    {
        for(int l=1,r=len;r<=n*2;l++,r++)
        {
            for(int k=l+1;k<r;k++)
            {
                dp[l][r]=max(dp[l][r],dp[l][k]+dp[k][r]+a[l]*a[r]*a[k]);
            }
        }
    }
    int ans=0;
    for(int i=1;i<=n;i++)
    {
        ans=max(ans,dp[i][i+n]);
    }
    printf("%d",ans);
    return 0;
}
